#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <omp.h>

#define STR_SIZE 256

/* maximum power density possible (say 300W for a 10mm x 10mm chip)	*/
#define MAX_PD	(3.0e6)
/* required precision in degrees	*/
#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
/* capacitance fitting factor	*/
#define FACTOR_CHIP	0.5

/* chip parameters	*/
float t_chip = 0.0005;
float chip_height = 0.016;
float chip_width = 0.016;
/* ambient temperature, assuming no package at all	*/
float amb_temp = 80.0;

void run(int argc, char** argv);

void fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);
	exit(1);
}

void writeoutput(float *vect, int grid_rows, int grid_cols, char *file){

	int i,j, index=0;
	FILE *fp;
	char str[STR_SIZE];

	if( (fp = fopen(file, "w" )) == 0 )
          printf( "The file was not opened\n" );

	for (i=0; i < grid_rows; i++) 
	 for (j=0; j < grid_cols; j++)
	 {

		 sprintf(str, "%d\t%g\n", index, vect[i*grid_cols+j]);
		 fputs(str,fp);
		 index++;
	 }

      fclose(fp);	
}

void readinput(float *vect, int grid_rows, int grid_cols, char *file){

  	int i,j;
	FILE *fp;
	char str[STR_SIZE];
	float val;

	if( (fp  = fopen(file, "r" )) ==0 )
            printf( "The file was not opened\n" );

	for (i=0; i <= grid_rows-1; i++) 
	 for (j=0; j <= grid_cols-1; j++)
	 {
		fgets(str, STR_SIZE, fp);
		if (feof(fp))
			fatal("not enough lines in file");
		if ((sscanf(str, "%f", &val) != 1))
			fatal("invalid file format");
		vect[i*grid_cols+j] = val;
	}

	fclose(fp);	
}

#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

void calculate_temp(int iteration, float *power, float *temp_src, float *temp_dst, int grid_cols, int grid_rows, int border_cols, int border_rows, float Cap, float Rx, float Ry, float Rz, float step, float time_elapsed){
	int i, j;
	for (i = 0; i < grid_rows; i++) {
		for (j = 0; j < grid_cols; j++) {
			int index = grid_cols * i + j;
			if (i >= border_rows && i < grid_rows - border_rows && j >= border_cols && j < grid_cols - border_cols) {
				temp_dst[index] = temp_src[index] + step / Cap * (power[index] + (temp_src[(i + 1) * grid_cols + j] + temp_src[(i - 1) * grid_cols + j] - 2.0 * temp_src[index]) * Ry + (temp_src[i * grid_cols + j + 1] + temp_src[i * grid_cols + j - 1] - 2.0 * temp_src[index]) * Rx + (amb_temp - temp_src[index]) * Rz);
			}
		}
	}
}

int compute_tran_temp(float *MatrixPower, float *MatrixTemp[2], int col, int row, int total_iterations, int num_iterations, int borderCols, int borderRows) {
	float grid_height = chip_height / row;
	float grid_width = chip_width / col;

	float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
	float Rx = grid_width / (2.0 * K_SI * t_chip * grid_height);
	float Ry = grid_height / (2.0 * K_SI * t_chip * grid_width);
	float Rz = t_chip / (K_SI * grid_height * grid_width);

	float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
	float step = PRECISION / max_slope;
	float t;
	float time_elapsed = 0.001;

	int src = 1, dst = 0;

	for (t = 0; t < total_iterations; t += num_iterations) {
		int temp = src;
		src = dst;
		dst = temp;
		for (int iter = 0; iter < MIN(num_iterations, total_iterations - t); iter++) {
			#pragma omp parallel for
			for (int i = borderRows; i < row - borderRows; i++) {
				for (int j = borderCols; j < col - borderCols; j++) {
					int index = col * i + j;
					MatrixTemp[dst][index] = MatrixTemp[src][index] + step / Cap * (MatrixPower[index] + (MatrixTemp[src][(i + 1) * col + j] + MatrixTemp[src][(i - 1) * col + j] - 2.0 * MatrixTemp[src][index]) * Ry + (MatrixTemp[src][i * col + j + 1] + MatrixTemp[src][i * col + j - 1] - 2.0 * MatrixTemp[src][index]) * Rx + (amb_temp - MatrixTemp[src][index]) * Rz);
				}
			}
			int temp2 = src;
			src = dst;
			dst = temp2;
		}
	}
	return dst;
}

void usage(int argc, char **argv)
{
	fprintf(stderr, "Usage: %s <grid_rows> <grid_cols> <pyramid_height> <sim_time> <temp_file> <power_file> <output_file>\n", argv[0]);
	fprintf(stderr, "\t<grid_rows>  - number of rows in the grid (positive integer)\n");
	fprintf(stderr, "\t<grid_cols> - number of columns in the grid (positive integer)\n");
	fprintf(stderr, "\t<pyramid_height> - pyramid height (positive integer)\n");
	fprintf(stderr, "\t<sim_time>   - number of iterations\n");
	fprintf(stderr, "\t<temp_file>  - name of the file containing the initial temperature values of each cell\n");
	fprintf(stderr, "\t<power_file> - name of the file containing the dissipated power values of each cell\n");
	fprintf(stderr, "\t<output_file> - name of the output file\n");
	exit(1);
}

int main(int argc, char** argv)
{
	run(argc, argv);
	return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
	int size;
	int grid_rows, grid_cols;
	float *FilesavingTemp, *FilesavingPower, *MatrixOut;
	char *tfile, *pfile, *ofile;

	int total_iterations = 60;
	int pyramid_height = 1;

	if (argc != 8)
		usage(argc, argv);
	if ((grid_rows = atoi(argv[1])) <= 0 ||
		(grid_cols = atoi(argv[2])) <= 0 ||
		(pyramid_height = atoi(argv[3])) <= 0 ||
		(total_iterations = atoi(argv[4])) <= 0)
		usage(argc, argv);

	tfile = argv[5];
	pfile = argv[6];
	ofile = argv[7];

	size = grid_rows * grid_cols;

	int borderCols = (pyramid_height) / 2;
	int borderRows = (pyramid_height) / 2;

	FilesavingTemp = (float *)malloc(size * sizeof(float));
	FilesavingPower = (float *)malloc(size * sizeof(float));
	MatrixOut = (float *)calloc(size, sizeof(float));

	if (!FilesavingPower || !FilesavingTemp || !MatrixOut)
		fatal("unable to allocate memory");

	readinput(FilesavingTemp, grid_rows, grid_cols, tfile);
	readinput(FilesavingPower, grid_rows, grid_cols, pfile);

	float *MatrixTemp[2], *MatrixPower;
	MatrixTemp[0] = (float *)malloc(size * sizeof(float));
	MatrixTemp[1] = (float *)malloc(size * sizeof(float));
	MatrixPower = (float *)malloc(size * sizeof(float));

	for (int i = 0; i < size; i++) {
		MatrixTemp[0][i] = FilesavingTemp[i];
		MatrixPower[i] = FilesavingPower[i];
	}

	int ret = compute_tran_temp(MatrixPower, MatrixTemp, grid_cols, grid_rows, total_iterations, pyramid_height, borderCols, borderRows);

	for (int i = 0; i < size; i++) {
		MatrixOut[i] = MatrixTemp[ret][i];
	}

	writeoutput(MatrixOut, grid_rows, grid_cols, ofile);

	free(MatrixPower);
	free(MatrixTemp[0]);
	free(MatrixTemp[1]);
	free(MatrixOut);
	free(FilesavingTemp);
	free(FilesavingPower);
}
